  ('lei_sancionada', 'federal', NULL, 'lei', '15.387', 2026, '2026-04-13', 'Altera a Lei nº 14.597, de 14 de junho de 2023 (Lei Geral do Esporte), para estabelecer a inscrição de programas de treinamento no Conselho Municipal dos Direitos da Criança e do Adolescente como requisito para caracterização de organização esportiva formadora de atletas.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15387.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15387', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15387.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.385', 2026, '2026-04-10', 'Altera a Lei nº 14.758, de 19 de dezembro de 2023, que institui a Política Nacional de Prevenção e Controle do Câncer no âmbito do Sistema Único de Saúde (SUS) e o Programa Nacional de Navegação da Pessoa com Diagnóstico de Câncer, para dispor sobre princípios e diretrizes para o desenvolvimento e regulação sanitária de novas tecnologias contra o câncer.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15385.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15385', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15385.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.386', 2026, '2026-04-10', 'Altera a Lei nº 14.597, de 14 de junho de 2023 (Lei Geral do Esporte), para instituir a Semana Nacional do Esporte.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15386.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15386', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15386.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.382', 2026, '2026-04-09', 'Institui o Dia Nacional de Proteção e Combate à Violência contra as Mulheres e Meninas Indígenas.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15382.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15382', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15382.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.383', 2026, '2026-04-09', 'Altera as Leis nºs 11.340, de 7 de agosto de 2006 (Lei Maria da Penha), 13.756, de 12 de dezembro de 2018, e 14.899, de 17 de junho de 2024, para estabelecer a monitoração eletrônica de agressores como medida protetiva autônoma e os critérios de prioridade para a monitoração eletrônica de agressores, prever causa de aumento de pena no crime de descumprimento de medida protetiva e dispor sobre campanhas e diretrizes orçamentárias.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15383.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15383', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15383.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.384', 2026, '2026-04-09', 'Altera a Lei nº 11.340, de 7 de agosto de 2006 (Lei Maria da Penha), o Decreto-Lei nº 2.848, de 7 de dezembro de 1940 (Código Penal), e a Lei nº 8.072, de 25 de julho de 1990 (Lei dos Crimes Hediondos), para prever a violência vicária entre as formas de violência doméstica e familiar, criar o tipo penal do vicaricídio e incluí-lo no rol dos crimes hediondos.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15384.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15384', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15384.htm"}'),
