  ('lei_sancionada', 'federal', NULL, 'lei', '15.357', 2026, '2026-03-20', 'Altera a Lei nº 5.991, de 17 de dezembro de 1973, que dispõe sobre o Controle Sanitário do Comércio de Drogas, Medicamentos, Insumos Farmacêuticos e Correlatos, e dá outras Providências, para dispor sobre a comercialização de medicamentos em farmácia ou drogaria instalada na área de venda de supermercados.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15357.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15357', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15357.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.356', 2026, '2026-03-19', 'Altera a Lei nº 13.999, de 18 de maio de 2020, para autorizar a utilização de recursos não comprometidos do Fundo Garantidor de Operações (FGO) para a cobertura de operações contratadas no âmbito do Programa Nacional de Fortalecimento da Agricultura Familiar (Pronaf).', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15356.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15356', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15356.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei complementar', '228', 2026, '2026-03-19', 'Dispõe sobre a redução de alíquotas da Contribuição para o PIS/Pasep e da Cofins incidentes sobre a indústria química e petroquímica, e altera as Leis nºs 11.196, de 21 de novembro de 2005, e 10.865, de 30 de abril de 2004.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/Leis/LCP/Lcp228.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:Lcp228', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/Leis/LCP/Quadro_Lcp.htm","planalto_href":"Lcp228.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.355', 2026, '2026-03-11', 'Institui a Política de Acolhimento e Manejo de Animais Resgatados (Amar); e altera as Leis nºs 9.605, de 12 de fevereiro de 1998, 12.334, de 20 de setembro de 2010, e 12.340, de 1º de dezembro de 2010.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/L15355.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15355', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2026/Lei/_leis2026.htm","planalto_href":"L15355.htm"}'),
