  ('lei_sancionada', 'federal', NULL, 'lei', '15.286', 2025, '2025-12-18', 'Inclui no calendário turístico oficial do País o evento Carnatal, no Município de Natal, no Estado do Rio Grande do Norte .', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/L15286.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15286', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/_leis2025.htm","planalto_href":"L15286.htm"}'),
