  ('lei_sancionada', 'federal', NULL, 'lei', '15.265', 2025, '2025-11-21', 'Institui o Regime Especial de Atualização e Regularização Patrimonial (Rearp), dispõe sobre a tributação das operações de empréstimo de títulos ou valores mobiliários no País e a tributação das operações de cobertura de riscos ( hedge ) e altera as Leis nºs 8.213, de 24 de julho de 1991, 9.430, de 27 de dezembro de 1996, 9.481, de 13 de agosto de 1997, 9.796, de 5 de maio de 1999, 10.150, de 21 de dezembro de 2000, 10.779, de 25 de novembro de 2003, e 14.818, de 16 de janeiro de 2024.', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/L15265.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15265', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/_leis2025.htm","planalto_href":"L15265.htm"}'),
