  ('lei_sancionada', 'federal', NULL, 'lei', '15.088', 2025, '2025-01-06', 'Altera a Lei nº 12.305, de 2 de agosto de 2010 (Lei de Resíduos Sólidos), para proibir a importação de resíduos sólidos e de rejeitos, ressalvados os casos que especifica.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/L15088.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15088', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/_leis2025.htm","planalto_href":"L15088.htm"}'),
