  ('lei_sancionada', 'federal', NULL, 'lei', '15.083', 2025, '2025-01-02', 'Altera a Lei nº 13.903, de 19 de novembro de 2019, para autorizar a criação de subsidiária da NAV Brasil Serviços de Navegação Aérea S.A. (NAV Brasil), nos termos que especifica, e dispõe sobre a possibilidade de alienação do seu controle acionário à União.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/L15083.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15083', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2025/Lei/_leis2025.htm","planalto_href":"L15083.htm"}'),
