  ('lei_sancionada', 'federal', NULL, 'lei', '15.045', 2024, '2024-12-16', 'Denomina “Ponte Nicanor Azambuja, João Dóglia e Diogo Madruga” a ponte sobre o Rio Camaquã, na rodovia BR-153, na divisa dos Municípios de Bagé e Caçapava do Sul, no Estado do Rio Grande do Sul.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L15045.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15045', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L15045.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '15.042', 2024, '2024-12-11', 'Institui o Sistema Brasileiro de Comércio de Emissões de Gases de Efeito Estufa (SBCE); e altera as Leis nºs 12.187, de 29 de dezembro de 2009, 12.651, de 25 de maio de 2012 (Código Florestal), 6.385, de 7 de dezembro de 1976 (Lei da Comissão de Valores Mobiliários), e 6.015, de 31 de dezembro de 1973 (Lei de Registros Públicos).', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L15042.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L15042', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L15042.htm"}'),
