  ('lei_sancionada', 'federal', NULL, 'lei', '14.924', 2024, '2024-07-12', 'Dispõe sobre a profissão de técnico em nutrição e dietética; e altera a Lei nº 6.583, de 20 de outubro de 1978, que cria os Conselhos Federal e Regionais de Nutricionistas e regula o seu funcionamento.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L14924.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14924', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L14924.htm"}'),
  ('lei_promulgada_pelo_legislativo', 'federal', NULL, 'lei', '14.922', 2024, '2024-07-11', 'Abre crédito extraordinário em favor do Ministério da Justiça e Segurança Pública, do Ministério do Meio Ambiente e Mudança do Clima, do Ministério do Desenvolvimento Agrário e Agricultura Familiar, do Ministério da Defesa, do Ministério do Desenvolvimento e Assistência Social, Família e Combate à Fome, do Ministério da Pesca e Aquicultura, do Ministério dos Direitos Humanos e da Cidadania e do Ministério dos Povos Indígenas, no valor de R$ 1.062.231.956,00 (um bilhão, sessenta e dois milhões, duzentos e trinta e um mil, novecentos e cinquenta e seis reais), para os fins que especifica.', 'RODRIGO PACHECO', 'mesa_legislativa', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L14922.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14922', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L14922.htm"}'),
