  ('lei_sancionada', 'federal', NULL, 'lei', '14.818', 2024, '2024-01-16', 'Institui incentivo financeiro-educacional, na modalidade de poupança, aos estudantes matriculados no ensino médio público; e altera a Lei nº 13.999, de 18 de maio de 2020, e a Lei nº 14.075, de 22 de outubro de 2020 . Mensagem de veto', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L14818.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14818', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L14818.htm"}'),
