  ('lei_sancionada', 'federal', NULL, 'lei', '14.806', 2024, '2024-01-11', 'Altera a Lei nº 6.360, de 23 de setembro de 1976, para obrigar os laboratórios farmacêuticos a incluírem nos rótulos, nas bulas e nos materiais destinados a propaganda e publicidade de seus produtos alerta sobre a presença de substâncias cujo uso seja considerado doping .', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L14806.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14806', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L14806.htm"}'),
