  ('lei_sancionada', 'federal', NULL, 'lei', '14.808', 2024, '2024-01-11', 'Confere ao Município de Torres, no Estado do Rio Grande do Sul, o título de Capital Nacional do Balonismo .', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/L14808.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14808', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2024/Lei/_leis2024.htm","planalto_href":"L14808.htm"}'),
