  ('lei_sancionada', 'federal', NULL, 'lei', '14.789', 2023, '2023-12-29', 'Dispõe sobre o crédito fiscal decorrente de subvenção para implantação ou expansão de empreendimento econômico; altera as Leis nºs 9.249, de 26 de dezembro de 1995, 14.592, de 30 de maio de 2023, e 14.754, de 12 de dezembro de 2023; e revoga dispositivos do Decreto-Lei nº 1.598, de 26 de dezembro de 1977, e das Leis nºs 10.637, de 30 de dezembro de 2002, 10.833, de 29 de dezembro de 2003, e 12.973, de 13 de maio de 2014 .', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14789.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14789', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14789.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '14.790', 2023, '2023-12-29', 'Dispõe sobre a modalidade lotérica denominada apostas de quota fixa; altera as Leis nºs 5.768, de 20 de dezembro de 1971, e 13.756, de 12 de dezembro de 2018, e a Medida Provisória nº 2.158-35, de 24 de agosto de 2001; revoga dispositivos do Decreto-Lei nº 204, de 27 de fevereiro de 1967; e dá outras providências. Mensagem de veto', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14790.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14790', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14790.htm"}'),
