  ('lei_sancionada', 'federal', NULL, 'lei', '14.709', 2023, '2023-10-25', 'Abre aos Orçamentos Fiscal e da Seguridade Social da União, em favor de diversos órgãos do Poder Executivo e de Operações Oficiais de Crédito, crédito suplementar no valor de R$ 483.178.068,00, para reforço de dotações constantes da Lei Orçamentária vigente.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14709.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14709', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14709.htm"}'),
