  ('lei_sancionada', 'federal', NULL, 'lei', '14.651', 2023, '2023-08-23', 'Altera o Decreto-Lei nº 1.455, de 7 de abril de 1976, as Leis nºs 10.833, de 29 de dezembro de 2003, e 14.286, de 29 de dezembro de 2021, para dispor sobre a aplicação e o julgamento da pena de perdimento de mercadoria, veículo e moeda.', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14651.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14651', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14651.htm"}'),
