  ('lei_sancionada', 'federal', NULL, 'lei', '14.659', 2023, '2023-08-23', 'Confere ao Município de Timbó, no Estado de Santa Catarina, o título de Capital Nacional do Cicloturismo.', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14659.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14659', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14659.htm"}'),
