  ('lei_sancionada', 'federal', NULL, 'lei', '14.628', 2023, '2023-07-20', 'Institui o Programa de Aquisição de Alimentos (PAA) e o Programa Cozinha Solidária; altera as Leis nºs 12.512, de 14 de outubro de 2011, e 14.133, de 1º de abril de 2021 (Lei de Licitações e Contratos Administrativos); e revoga dispositivos das Leis nºs 11.718, de 20 de junho de 2008, 11.775, de 17 de setembro de 2008, 12.512, de 14 de outubro de 2011, e 14.284, de 29 de dezembro de 2021 .', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14628.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14628', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14628.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '14.626', 2023, '2023-07-19', 'Altera a Lei nº 10.048, de 8 de novembro de 2000, e a Lei nº 10.205, de 21 de março de 2001, para prever atendimento prioritário a pessoas com transtorno do espectro autista ou com mobilidade reduzida e a doadores de sangue e reserva de assento em veículos de empresas públicas de transporte e de concessionárias de transporte coletivo nos dois primeiros casos.', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14626.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14626', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14626.htm"}'),
