  ('lei_sancionada', 'federal', NULL, 'lei', '14.614', 2023, '2023-07-03', 'Altera a Lei nº 14.597, de 14 de junho de 2023 (Lei Geral do Esporte), para garantir às atletas gestantes ou puérperas, no âmbito da Bolsa-Atleta, o respeito à maternidade e aos direitos que as protegem .', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14614.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14614', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14614.htm"}'),
