  ('lei_sancionada', 'federal', NULL, 'lei complementar', '198', 2023, '2023-06-28', 'Altera a Lei Complementar nº 91, de 22 de dezembro de 1997, para manter os coeficientes do Fundo de Participação dos Municípios (FPM) de Municípios com redução populacional aferida em censo demográfico, aplicando redutor financeiro sobre eventuais ganhos, na forma e no prazo que especifica; e altera a Lei nº 14.133, de 1º de abril de 2021 (Lei de Licitações e Contratos Administrativos).', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/Leis/LCP/Lcp198.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:Lcp198', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/Leis/LCP/Quadro_Lcp.htm","planalto_href":"Lcp198.htm"}'),
