  ('lei_sancionada', 'federal', NULL, 'lei', '14.604', 2023, '2023-06-20', 'Denomina “Ponte Joaquim Machado de Souza” a ponte sobre o rio Envira na rodovia BR-364, no Município de Feijó, Estado do Acre.', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14604.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14604', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14604.htm"}'),
