  ('lei_sancionada', 'federal', NULL, 'lei', '14.593', 2023, '2023-06-02', 'Altera a Lei nº 13.693, de 10 de julho de 2018, para instituir a Semana Nacional da Informação, Capacitação e Pesquisa sobre Doenças Raras e alterar a denominação do Dia Nacional de Doenças Raras.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14593.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14593', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14593.htm"}'),
