  ('lei_sancionada', 'federal', NULL, 'lei', '14.554', 2023, '2023-04-20', 'Altera as Leis nºs 13.999, de 18 de maio de 2020, 14.166, de 10 de junho de 2021, 11.540, de 12 de novembro de 2007, e 14.042, de 19 de agosto de 2020, para flexibilizar e aprimorar as condições de contratação e de renegociação das operações do Programa Nacional de Apoio às Microempresas e Empresas de Pequeno Porte (Pronampe), ampliar o prazo para a renegociação extraordinária de débitos no âmbito do Fundo Constitucional de Financiamento do Norte (FNO), do Fundo Constitucional de Financiamento do Nordeste (FNE) e do Fundo Constitucional de Financiamento do Centro-Oeste (FCO), facilitar o fomento à ciência e tecnologia e aprimorar o Programa Emergencial de Acesso a Crédito (Peac); e revoga dispositivos das Leis nºs 14.115, de 29 de dezembro de 2020, 14.161, de 2 de junho de 2021, e 14.257, de 1º de dezembro de 2021.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14554.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14554', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14554.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '14.550', 2023, '2023-04-19', 'Altera a Lei nº 11.340, de 7 de agosto de 2006 (Lei Maria da Penha), para dispor sobre as medidas protetivas de urgência e estabelecer que a causa ou a motivação dos atos de violência e a condição do ofensor ou da ofendida não excluem a aplicação da Lei.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14550.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14550', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14550.htm"}'),
  ('lei_promulgada_pelo_legislativo', 'federal', NULL, 'lei', '14.547', 2023, '2023-04-13', 'Altera a Lei nº 12.973, de 13 de maio de 2014, para ampliar o prazo de vigência do crédito presumido e do regime de consolidação.', 'VENEZIANO VITAL DO RÊGO', 'mesa_legislativa', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14547.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14547', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14547.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '14.548', 2023, '2023-04-13', 'Altera a Lei nº 8.069, de 13 de julho de 1990 (Estatuto da Criança e do Adolescente), para compatibilizá-la com a Lei nº 12.127, de 17 de dezembro de 2009, que criou o Cadastro Nacional de Crianças e Adolescentes Desaparecidos, e com a Lei nº 13.812, de 16 de março de 2019, que instituiu a Política Nacional de Busca de Pessoas Desaparecidas e criou o Cadastro Nacional de Pessoas Desaparecidas .', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14548.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14548', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14548.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '14.549', 2023, '2023-04-13', 'Institui a Semana Nacional do Uso Consciente da Água .', 'GERALDO JOSÉ RODRIGUES ALCKMIN FILHO', 'outro', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14549.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14549', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14549.htm"}'),
  ('lei_promulgada_pelo_legislativo', 'federal', NULL, 'lei', '14.544', 2023, '2023-04-04', 'Dispõe sobre a gestão e a operacionalização dos pedidos das indenizações previstas no art. 3º da Lei nº 6.194, de 19 de dezembro de 1974, com vistas a assegurar a sua continuidade; e altera a Lei nº 14.075, de 22 de outubro de 2020.', 'RODRIGO PACHECO', 'mesa_legislativa', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14544.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14544', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14544.htm"}'),
