  ('lei_sancionada', 'federal', NULL, 'lei', '14.546', 2023, '2023-04-04', 'Altera a Lei nº 11.445, de 5 de janeiro de 2007 (Lei de Saneamento Básico), para estabelecer medidas de prevenção a desperdícios, de aproveitamento das águas de chuva e de reúso não potável das águas cinzas. Mensagem de veto', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14546.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14546', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14546.htm"}'),
