  ('lei_sancionada', 'federal', NULL, 'lei', '14.530', 2023, '2023-01-10', 'Altera a Lei nº 11.930, de 22 de abril de 2009, para facilitar a localização de doadores cadastrados no Registro Nacional de Doadores de Medula Óssea (Redome). Mensagem de veto', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14530.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14530', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14530.htm"}'),
  ('lei_sancionada', 'federal', NULL, 'lei', '14.531', 2023, '2023-01-10', 'Altera as Leis nºs 13.675, de 11 de junho de 2018, que cria a Política Nacional de Segurança Pública e Defesa Social (PNSPDS), e 13.819, de 26 de abril de 2019, que institui a Política Nacional de Prevenção da Automutilação e do Suicídio, para dispor sobre a implementação de ações de assistência social, a promoção da saúde mental e a prevenção do suicídio entre profissionais de segurança pública e defesa social e para instituir as diretrizes nacionais de promoção e defesa dos direitos humanos dos profissionais de segurança pública e defesa social; e dá outras providências. Mensagem de veto', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14531.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14531', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14531.htm"}'),
