  ('lei_sancionada', 'federal', NULL, 'lei', '14.517', 2023, '2023-01-04', 'Institui o Dia Nacional dos Trabalhadores em Entidades Culturais, Recreativas e Conexas, a ser comemorado na segunda segunda-feira do mês de maio de cada ano.', 'LUIZ INÁCIO LULA DA SILVA', 'titular', 'https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/L14517.htm', 'Planalto - Legislação Federal', NULL, 'Planalto:L14517', '{"source":"Planalto","data_real":true,"fluxo":"5B","coverage_id":"lula-federal-atual-completo-leis-ordinarias-complementares-2023-2026-04-28","coverage_label":"Leis ordinarias e complementares federais do mandato presidencial iniciado em 2023, indexadas e verificadas no Planalto ate 28/04/2026","coverage_scope":"inventario_completo_federal_atual_2023_2026","index_url":"https://www.planalto.gov.br/ccivil_03/_Ato2023-2026/2023/Lei/_leis2023.htm","planalto_href":"L14517.htm"}'),
